import{_ as e,o as a,c as t,j as r,a as n,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"网络君子六艺","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/网络君子六艺.md","filePath":"4.资源分区/6.技艺及称号/杂项/网络君子六艺.md"}'),s={name:"4.资源分区/6.技艺及称号/杂项/网络君子六艺.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"网络君子六艺",tabindex:"-1"},[n("网络君子六艺 "),r("a",{class:"header-anchor",href:"#网络君子六艺","aria-label":'Permalink to "网络君子六艺"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风025春节版")])])],-1),p('<h1 id="网络君子六艺-1" tabindex="-1">网络君子六艺 <a class="header-anchor" href="#网络君子六艺-1" aria-label="Permalink to &quot;网络君子六艺&quot;">​</a></h1><p>急<br> 价格：D+500<br> 概述：将你在混沌的网络之海学习到的网络六艺之一化为攻击的手段，通过言语将敌人的理智狠狠消灭，化作红温状态，然后说出“急了”完成绝杀。<br> 效果：你获得一种新的攻击能力，通过风度+社交+专业：交际+辅助专业：察言观色进行攻击检定，能力的攻击射程为20米，武器伤害为3L，为精神伤害，这次攻击可以额外在攻击范围内选择一个攻击目标，攻击附加1点亢奋异常点，正常豁免。<br> ========</p><p>典<br> 价格：D+500<br> 概述：将你在混沌的网络之海学习到的网络六艺之一化为防御的手段，绝不会被古老的套路所打败。<br> 动作：移动<br> 限制：一场景一次<br> 持续：立即<br> 效果：你进入一个类招架形态，在你的回合时处于你视野的敌人对你发动攻击时，你可以哈哈大笑，发出一声“典”，然后你以反射动作调用该技艺进行一次招架，在这次招架时你可以强行使攻击你的敌人重掷该攻击检定，但你必须接受重置的结果。<br> ========</p><p>乐<br> 价格：D+500<br> 概述：将你在混沌的网络之海学习到的网络六艺之一化为强化精神的技艺，但由于某些名人的原因会导致使用者遭到的枪械伤害增加。<br> 动作：自由<br> 限制：一轮一次<br> 持续：一轮<br> 效果：爱笑的男孩运气不会太差：你常态获得一点机运加值，说服，交际和哄骗检定+1<br> 突然乐：你不自觉的嘴角上扬，你的下一个意志豁免检定+2直到这轮结束。<br> 脑洞大开：当你未穿戴保护头颅的防具并乘坐轻型载具时，你具有8点枪械伤害易伤，同时该技艺暂时失效直到你脱离这种状态。<br> ========</p><p>赢<br> 价格：D+500<br> 概述：将你在混沌的网络之海学习到的网络六艺之一化为强化自己的技艺，但要小心反噬。<br> 动作：自由<br> 限制：无<br> 持续：一场景<br> 效果：在战斗开始前大喊出：”会赢的“，然后你的先攻加+6，攻击命中时，额外追加1点精神伤害，<br> 没有让你尽兴真是抱歉啊：你在受到攻击腹部的攻击时，对方不会受到特殊部位攻击减值。<br> ========</p><p>孝<br> 价格：D+1000<br> 概述：将你在混沌的网络之海学习到的网络六艺之一转化为思维控制，将敌人打为孝子，从而更容易攻击他。<br> 动作：标准<br> 限制：一场景一次<br> 持续：一场景<br> 效果：使用者进行一次攻击，被命中者以意志豁免对抗这次攻击的伤害出目，如果失败，那么你可以操控他对自己喜欢但不太被大众认同的事务立刻表现出强烈的安利热情，即使是在不合时宜的情形也会如此，这是一个D级的思维控制效果，然后有感知到这种情形的单位在场的情况下，你的攻击具有一点额外的附加成功，且具有5点威猛。<br> ========</p><p>麻<br> 价格：D+500<br> 概述：将你在混沌的网络之海学习到的网络六艺之一转化为对抗身体疲乏的能力，甚至是传递给他人<br> 效果：使用者的强韧豁免获得4加值，你的攻击附带2点疲乏，这是一个D级诅咒来源的效果，正常豁免。<br> ========</p><p>六<br> 价格 D+500<br> 概述：“你说这六个字就是现在的君子六艺？”<br> “是的。”<br> 老者沉默良久，吐出一个字<br> “六。”<br> 条件：购买麻，孝，乐，赢，典，急。<br> 效果：使用者获得<br> 1高速，<br> 1威猛，<br> 1破甲，<br> 1破魔，<br> 1力场防御，<br> 1网上君子六艺防御（无名防御）<br> ========</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const D=e(s,[["render",o]]);export{f as __pageData,D as default};
